def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    from pptx.dml.color import RGBColor, MSO_COLOR_TYPE

    def is_red_color(color_obj):
        """Check if a color is red (accepts various shades of red)."""
        if not color_obj or color_obj.type != MSO_COLOR_TYPE.RGB:
            return False

        color = color_obj.rgb
        r, g, b = color[0], color[1], color[2]

        # Accept various shades of red:
        # - Pure red: (255, 0, 0)
        # - Dark red: (238, 0, 0) - which is what we found in the file
        # - Other common reds: Allow high red (>200) with low green and blue (<50)
        return r >= 200 and g <= 50 and b <= 50

    prs = Presentation(modified_ppt_path)
    found_title = False

    # Check the first slide first (most likely where the main title should be changed)
    for slide_num, slide in enumerate(prs.slides, 1):
        for shape in slide.shapes:
            if shape.has_text_frame:
                text = shape.text_frame.text.strip()
                if text == 'Accounting Equation':
                    found_title = True
                    runs = []
                    for paragraph in shape.text_frame.paragraphs:
                        runs += paragraph.runs

                    # If no runs, fallback to paragraph-level font
                    if not runs:
                        for paragraph in shape.text_frame.paragraphs:
                            font = paragraph.font
                            if font.color and is_red_color(font.color):
                                return (f"Title color is red on slide {slide_num}.", 1.0)
                        # Continue to next slide if this title is not red
                        continue

                    # For runs, check all runs are red
                    all_red = True
                    for run in runs:
                        font = run.font
                        if not font.color or not is_red_color(font.color):
                            all_red = False
                            break

                    if all_red:
                        return (f"Title color is red on slide {slide_num}.", 1.0)
                    # Continue to next slide if this title is not fully red

    if not found_title:
        return ("Could not find 'Accounting Equation' title in PPT.", 0.0)

    # If we found titles but none were red
    return ("Found 'Accounting Equation' titles but none have red color.", 0.0)

def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    orig_prs = Presentation(original_ppt_path)
    mod_prs = Presentation(modified_ppt_path)
    original_titles = set()
    modified_titles = set()
    for slide_idx, slide in enumerate(orig_prs.slides):
        for shape in slide.shapes:
            if shape.has_text_frame:
                if shape.text_frame.text.strip() == 'Accounting Equation':
                    original_titles.add((slide_idx, shape.text_frame.text.strip()))
    for slide_idx, slide in enumerate(mod_prs.slides):
        for shape in slide.shapes:
            if shape.has_text_frame:
                if shape.text_frame.text.strip() == 'Accounting Equation':
                    modified_titles.add((slide_idx, shape.text_frame.text.strip()))
    if not original_titles:
        return ("No 'Accounting Equation' title found in original presentation.", 0.0)
    if not modified_titles:
        return ("'Accounting Equation' title has been removed.", 0.0)
    # There should be same number of such titles in same slides (by index)
    orig_slide_idxs = set([idx for idx, _ in original_titles])
    mod_slide_idxs = set([idx for idx, _ in modified_titles])
    if orig_slide_idxs != mod_slide_idxs:
        return ("Title has been moved or duplicated/deleted.", 0.0)
    return ("Title text and slide unchanged except for color.", 1.0)

def compute_score() -> tuple[str, float]:
    """Return (message, score) enforcing that ONLY allowed change is font color of
    the title text 'Accounting Equation' on slide 1 (index 0). No other slide or
    element may change (text, shape count, structure, or color). If nothing changed
    that's also acceptable.
    """
    p = ppt_diff

    # Hard disallow structural presentation-level changes first
    if p.added_slides or p.removed_slides:
        return ("Extraneous slides were added or removed.", 0.0)
    if p.added_animations or p.removed_animations:
        return ("Extraneous animations were added or removed.", 0.0)
    if p.added_transitions:
        return ("Extraneous transitions were added.", 0.0)

    from pptx import Presentation
    try:
        orig_prs = Presentation(original_ppt_path)
        mod_prs = Presentation(modified_ppt_path)
    except Exception:
        return ("Failed to open presentations.", 0.0)

    if len(orig_prs.slides) != len(mod_prs.slides):
        return ("Slide count changed.", 0.0)

    def is_target_title(shape) -> bool:
        if not getattr(shape, 'has_text_frame', False):
            return False
        try:
            return shape.text_frame.text.strip() == 'Accounting Equation'
        except Exception:
            return False

    def run_signatures(shape):
        """List[(run_text, color_signature)] for a text shape.
        color_signature favors explicit RGB else falls back to (theme, type).
        """
        sigs = []
        if not getattr(shape, 'has_text_frame', False):
            return sigs
        try:
            for para in shape.text_frame.paragraphs:
                for run in para.runs:
                    rgb_val = None
                    theme = None
                    ctype = None
                    try:
                        color = run.font.color
                        if color is not None:
                            rgb = getattr(color, 'rgb', None)
                            if rgb is not None:
                                try:
                                    rgb_val = str(rgb)  # 'RRGGBB'
                                except Exception:
                                    rgb_val = repr(rgb)
                            theme = getattr(color, 'theme_color', None)
                            ctype = getattr(color, 'type', None)
                    except Exception:
                        pass
                    sigs.append((run.text, (rgb_val, str(theme), str(ctype))))
        except Exception:
            # Fallback single signature if iteration fails
            try:
                sigs.append((shape.text_frame.text, (None, None, None)))
            except Exception:
                pass
        return sigs

    observed_allowed_change = False

    for idx in range(len(orig_prs.slides)):
        old_slide = orig_prs.slides[idx]
        new_slide = mod_prs.slides[idx]
        old_shapes = old_slide.shapes
        new_shapes = new_slide.shapes

        if len(old_shapes) != len(new_shapes):
            return (("Slide 1 shape count changed (not allowed)." if idx == 0 else f"Shape count changed on slide {idx+1} (not allowed)."), 0.0)

        for o_shape, n_shape in zip(old_shapes, new_shapes):
            o_has = getattr(o_shape, 'has_text_frame', False)
            n_has = getattr(n_shape, 'has_text_frame', False)
            if o_has != n_has:
                return (("Slide 1 structure changed (not allowed)." if idx == 0 else f"Structure changed on slide {idx+1} (not allowed)."), 0.0)
            if not o_has:
                # Non-text shapes: we only verify presence/ordering via counts & pairing already
                continue

            old_text = o_shape.text_frame.text
            new_text = n_shape.text_frame.text
            if old_text != new_text:
                # Any text difference is disallowed (even title text) because only color may change
                return (("Text changed on slide 1 (not allowed)." if idx == 0 else f"Text changed on slide {idx+1} (not allowed)."), 0.0)

            old_sig = run_signatures(o_shape)
            new_sig = run_signatures(n_shape)
            # Compare run segmentation & text sequence
            if len(old_sig) != len(new_sig) or any(ot != nt for (ot, _), (nt, _) in zip(old_sig, new_sig)):
                return (("Run segmentation/text changed on slide 1 (not allowed)." if idx == 0 else f"Run segmentation/text changed on slide {idx+1} (not allowed)."), 0.0)

            # Compare colors
            colors_changed = any(oc != nc for (_, oc), (_, nc) in zip(old_sig, new_sig))

            if colors_changed:
                if idx == 0 and is_target_title(o_shape):
                    # Allowed color change (title only on slide 1)
                    observed_allowed_change = True
                else:
                    return (("Non-title color changed on slide 1 (not allowed)." if idx == 0 else f"Color changed on slide {idx+1} (not allowed)."), 0.0)

    # Success whether or not a title color change actually occurred (requirement allows but doesn't mandate it)
    return ("No extraneous changes detected.", 1.0)
